#!/usr/bin/env python3

from __future__ import annotations

import subprocess
from pathlib import Path

try:
    from scripts.repo_layout import support_dir
except ModuleNotFoundError:
    from repo_layout import support_dir


class RepoFileListingError(SystemExit):
    pass


def _decode_output(value: bytes) -> str:
    return value.decode("utf-8", errors="replace")


def git_list_repo_files(
    repo_root: Path,
    *,
    include_untracked: bool = True,
    require_git: bool = False,
) -> list[Path] | None:
    args = ["git", "ls-files", "-z", "--cached"]
    if include_untracked:
        args.extend(["--others", "--exclude-standard"])
    result = subprocess.run(
        args,
        cwd=repo_root,
        check=False,
        capture_output=True,
    )
    if result.returncode != 0:
        if require_git:
            raise RepoFileListingError(
                "repo file listing failed\n"
                f"command: {' '.join(args)}\n"
                f"exit_code: {result.returncode}\n"
                f"STDOUT:\n{_decode_output(result.stdout)}\n"
                f"STDERR:\n{_decode_output(result.stderr)}"
            )
        return None
    return sorted(repo_root / rel.decode("utf-8") for rel in result.stdout.split(b"\0") if rel)


def iter_repo_files(
    repo_root: Path,
    *,
    include_untracked: bool = True,
    require_git: bool = False,
) -> list[Path]:
    paths = git_list_repo_files(
        repo_root,
        include_untracked=include_untracked,
        require_git=require_git,
    )
    if paths is not None:
        return [path for path in paths if path.is_file()]

    candidates: list[Path] = []
    for path in repo_root.rglob("*"):
        if path.is_file():
            candidates.append(path)
    return sorted(candidates)


_SUPPORT_PATTERN_PREFIX = "skills/support/"


def _split_support_patterns(patterns: tuple[str, ...]) -> tuple[list[str], list[str]]:
    standard: list[str] = []
    support: list[str] = []
    for pattern in patterns:
        if pattern.startswith(_SUPPORT_PATTERN_PREFIX):
            support.append(pattern.removeprefix(_SUPPORT_PATTERN_PREFIX))
        else:
            standard.append(pattern)
    return standard, support


def iter_matching_repo_files(
    repo_root: Path,
    patterns: tuple[str, ...],
    *,
    include_untracked: bool = True,
    require_git: bool = False,
) -> list[Path]:
    standard_patterns, support_subpatterns = _split_support_patterns(patterns)
    support_root = support_dir(repo_root)
    support_is_external = support_root != (repo_root / "skills" / "support").resolve()
    if not support_is_external:
        standard_patterns.extend(_SUPPORT_PATTERN_PREFIX + sub for sub in support_subpatterns)
        support_subpatterns = []

    matches: list[Path] = []
    seen: set[Path] = set()

    git_paths = git_list_repo_files(
        repo_root,
        include_untracked=include_untracked,
        require_git=require_git,
    )
    if git_paths is not None:
        allowed = {path for path in git_paths if path.is_file()}
        for pattern in standard_patterns:
            for path in repo_root.glob(pattern):
                if not path.is_file() or path not in allowed or path in seen:
                    continue
                seen.add(path)
                matches.append(path)
    else:
        for pattern in standard_patterns:
            for path in repo_root.glob(pattern):
                if not path.is_file() or path in seen:
                    continue
                seen.add(path)
                matches.append(path)

    for sub in support_subpatterns:
        for path in support_root.glob(sub):
            if not path.is_file() or path in seen:
                continue
            seen.add(path)
            matches.append(path)

    return sorted(matches)

from __future__ import annotations

import io
import re
import tokenize
from pathlib import Path
from typing import Any

from scripts.repo_file_listing import iter_repo_files
from scripts.vendored_path_lib import is_vendored, vendored_prefixes

IGNORED_PARTS = {
    ".git",
    ".mypy_cache",
    ".pytest_cache",
    ".ruff_cache",
    ".venv",
    "__pycache__",
    "node_modules",
}
TEXT_SUFFIXES = {".cjs", ".js", ".jsx", ".mjs", ".py", ".pyi", ".ts", ".tsx"}
PYTHON_NOQA_RE = re.compile(r"# noqa(?::\s*(?P<codes>[A-Za-z0-9_,\s-]+))?", re.IGNORECASE)
PYTHON_RUFF_FILE_RE = re.compile(r"^\s*#\s*ruff:\s*noqa(?:\s*:\s*(?P<codes>.*))?\s*$", re.IGNORECASE)
PYTHON_PYLINT_RE = re.compile(r"#\s*pylint:\s*disable=(?P<codes>[^#]+)", re.IGNORECASE)
ESLINT_RE = re.compile(
    r"(?:^|\s)(?://|/\*)\s*eslint-disable(?P<scope>-next-line|-line)?(?:\s+(?P<codes>[^*\n]+?))?\s*(?:\*/)?$",
    re.IGNORECASE,
)

# Advisory interpretation contract (see skills/shared/references/
# advisory-interpretation-contract.md): suppression pressure is an
# inference-layer trend, so the inventory self-declares blind spots and the
# question the `quality` consumer must answer before treating it as debt.
INTERPRETATION = {
    "measures": (
        "lint-suppression sites — `# noqa`, `# ruff: noqa`, `# pylint: disable`, and "
        "`eslint-disable` comments, counted by scope (file/inline), blanket-vs-coded, "
        "and tool"
    ),
    "proxy_for": "normalized lint debt — suppressions that defer a structural fix instead of paying it",
    "blind_spots": (
        "counts suppression comments, not their justification — an intentional, "
        "provenance-bearing file-level ignore (e.g. a launcher's import-order "
        "`# ruff: noqa: E402`) counts the same as undocumented debt; it cannot read "
        "whether a suppression is cheaper than the fix it defers"
    ),
    "interpretation_question": (
        "which of these suppressions are justified, provenance-bearing deferrals "
        "versus normalized debt THIS repo should structurally fix?"
    ),
}


def _iter_candidate_files(repo_root: Path, vendored: list[str]) -> list[Path]:
    paths: list[Path] = []
    for path in iter_repo_files(repo_root):
        if not path.is_file():
            continue
        if any(part in IGNORED_PARTS for part in path.relative_to(repo_root).parts):
            continue
        if path.suffix.lower() not in TEXT_SUFFIXES:
            continue
        if is_vendored(repo_root, path, vendored):
            continue
        paths.append(path)
    return sorted(paths)


def _parse_codes(raw: str | None) -> list[str]:
    if not raw:
        return []
    cleaned = raw.replace("*/", " ").replace("(", " ").replace(")", " ")
    return [part.strip() for part in re.split(r"[,\s]+", cleaned) if part.strip()]


def _recommendation(*, tool: str, file_level: bool, blanket: bool) -> str:
    if blanket:
        return "Blanket lint suppression is a strong smell; prefer a structural fix or a rule-specific suppression with a clear reason."
    if file_level and tool == "ruff":
        return "File-level Ruff suppression deserves explicit review; prefer packaging or launcher structure that makes the import order legal."
    if file_level:
        return "File-level lint suppression should be localized or justified before it becomes normal maintenance debt."
    return "Inline suppression should stay narrow, rule-specific, and cheaper than the structural fix it is deferring."


def _record_finding(
    findings: list[dict[str, Any]],
    *,
    repo_root: Path,
    path: Path,
    line_no: int,
    tool: str,
    scope: str,
    codes: list[str],
    raw: str,
) -> None:
    findings.append(
        {
            "path": path.relative_to(repo_root).as_posix(),
            "line": line_no,
            "tool": tool,
            "scope": scope,
            "codes": codes,
            "blanket": not codes,
            "recommendation": _recommendation(tool=tool, file_level=scope == "file", blanket=not codes),
            "snippet": raw.strip(),
        }
    )


def _inventory_python_comments(repo_root: Path, path: Path, text: str, findings: list[dict[str, Any]]) -> bool:
    try:
        tokens = tokenize.generate_tokens(io.StringIO(text).readline)
    except tokenize.TokenError:
        return False

    for token in tokens:
        if token.type != tokenize.COMMENT:
            continue
        line_no, column = token.start
        comment = token.string
        raw = token.line
        if match := PYTHON_RUFF_FILE_RE.match(comment):
            _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="ruff", scope="file", codes=_parse_codes(match.group("codes")), raw=raw)
        for match in PYTHON_PYLINT_RE.finditer(comment):
            _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="pylint", scope="file" if column == 0 else "inline", codes=_parse_codes(match.group("codes")), raw=raw)
        for match in PYTHON_NOQA_RE.finditer(comment):
            if "ruff:" in comment[: match.start()].lower():
                continue
            scope = "file" if column == 0 and comment.lstrip().lower().startswith("# noqa") else "inline"
            _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="noqa", scope=scope, codes=_parse_codes(match.group("codes")), raw=raw)
    return True


def _inventory_text_lines(repo_root: Path, path: Path, text: str, findings: list[dict[str, Any]]) -> None:
    for line_no, line in enumerate(text.splitlines(), start=1):
        for match in ESLINT_RE.finditer(line):
            _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="eslint", scope="file" if match.group("scope") is None else "inline", codes=_parse_codes(match.group("codes")), raw=line)


def inventory_lint_ignores(repo_root: Path, vendored_paths: list[str] | None = None) -> dict[str, Any]:
    findings: list[dict[str, Any]] = []
    vendored = vendored_prefixes(vendored_paths)
    for path in _iter_candidate_files(repo_root, vendored):
        text = path.read_text(encoding="utf-8", errors="replace")
        lower_text = text.lower()
        has_eslint_marker = "eslint-disable" in lower_text
        has_python_marker = "noqa" in lower_text or "pylint:" in lower_text or "ruff:" in lower_text
        if not has_eslint_marker and not has_python_marker:
            continue

        is_python = path.suffix.lower() in {".py", ".pyi"}
        handled_python = is_python and has_python_marker and _inventory_python_comments(repo_root, path, text, findings)
        if handled_python:
            if has_eslint_marker:
                _inventory_text_lines(repo_root, path, text, findings)
            continue

        if has_eslint_marker:
            _inventory_text_lines(repo_root, path, text, findings)
        if not is_python or not has_python_marker:
            continue

        for line_no, line in enumerate(text.splitlines(), start=1):
            if match := PYTHON_RUFF_FILE_RE.match(line):
                _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="ruff", scope="file", codes=_parse_codes(match.group("codes")), raw=line)
            for match in PYTHON_PYLINT_RE.finditer(line):
                _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="pylint", scope="file" if line.lstrip().startswith("#") else "inline", codes=_parse_codes(match.group("codes")), raw=line)
            for match in PYTHON_NOQA_RE.finditer(line):
                if "ruff:" in line[: match.start()].lower():
                    continue
                stripped = line.lstrip()
                scope = "file" if stripped.startswith("#") and stripped.lower().startswith("# noqa") else "inline"
                _record_finding(findings, repo_root=repo_root, path=path, line_no=line_no, tool="noqa", scope=scope, codes=_parse_codes(match.group("codes")), raw=line)

    return {
        "repo_root": str(repo_root),
        "summary": {
            "ignore_count": len(findings),
            "files_with_ignores": len({finding["path"] for finding in findings}),
            "blanket_count": sum(1 for finding in findings if finding["blanket"]),
            "file_level_count": sum(1 for finding in findings if finding["scope"] == "file"),
            "inline_count": sum(1 for finding in findings if finding["scope"] == "inline"),
            "by_tool": {
                tool: sum(1 for finding in findings if finding["tool"] == tool)
                for tool in sorted({finding["tool"] for finding in findings})
            },
        },
        "review_prompts": [
            "Treat lint suppressions as advisory debt inventory, not invisible background noise.",
            "Blanket or file-level ignores are stronger review targets than narrow rule-specific inline suppressions.",
            "When the same ignore shape repeats, prefer a structural seam over proliferating more comments.",
        ],
        "interpretation": dict(INTERPRETATION),
        "findings": findings,
    }

#!/usr/bin/env python3

from __future__ import annotations

import argparse
import ast
import fnmatch
import json
import sys
from pathlib import Path

sys.path.insert(0, str(Path(__file__).resolve().parent))
from git_inventory_lib import GitFileListingError, visible_repo_files  # noqa: E402

GIT_AWARE_MARKERS = (
    "git ls-files",
    "git_visible_repo_files",
    "_git_visible_repo_files",
    "visible_repo_files",
    "git_list_repo_files",
    "iter_repo_files",
    "iter_matching_repo_files",
    "--exclude-standard",
    "check-ignore",
    "pathspec",
)
DEFAULT_PATH_GLOBS = (
    "skills/public/quality/scripts/*.py",
    "skills/public/quality/references/*.py",
    "scripts/*inventory*.py",
    "scripts/*quality*.py",
    "scripts/*scan*.py",
)
REPO_ROOT_NAMES = {"repo_root", "root", "REPO_ROOT"}


class InventoryError(SystemExit):
    pass


def matches_any(path: str, patterns: tuple[str, ...]) -> bool:
    return any(fnmatch.fnmatch(path, pattern) for pattern in patterns)


def candidate_files(
    repo_root: Path,
    path_globs: tuple[str, ...],
    *,
    require_git: bool = False,
) -> list[Path]:
    try:
        visible_files = visible_repo_files(
            repo_root,
            require_git=require_git,
            context="gitignore scan hygiene file listing",
        )
    except GitFileListingError as exc:
        raise InventoryError(str(exc)) from exc
    candidates: list[Path] = []
    seen: set[Path] = set()
    for pattern in path_globs:
        for path in repo_root.glob(pattern):
            if not path.is_file() or path in seen:
                continue
            seen.add(path)
            if visible_files is not None and path not in visible_files:
                continue
            candidates.append(path)
    return sorted(candidates)


def _is_repo_root_name(node: ast.AST) -> bool:
    return isinstance(node, ast.Name) and node.id in REPO_ROOT_NAMES


def _first_call_arg(node: ast.Call) -> ast.AST | None:
    return node.args[0] if node.args else None


def _call_label(node: ast.Call, source: str) -> str:
    segment = ast.get_source_segment(source, node)
    return segment or f"line {getattr(node, 'lineno', 1)}"


def _is_repo_wide_glob(node: ast.Call) -> bool:
    if not isinstance(node.func, ast.Attribute):
        return False
    if node.func.attr == "rglob":
        return _is_repo_root_name(node.func.value)
    if node.func.attr != "glob" or not _is_repo_root_name(node.func.value):
        return False
    arg = _first_call_arg(node)
    if isinstance(arg, ast.Constant) and isinstance(arg.value, str):
        return "**" in arg.value
    return isinstance(arg, ast.Name)


def _is_repo_walk(node: ast.Call) -> bool:
    if not isinstance(node.func, ast.Attribute) or node.func.attr != "walk":
        return False
    if isinstance(node.func.value, ast.Name) and node.func.value.id == "os":
        return bool(node.args and _is_repo_root_name(node.args[0]))
    return False


def _parent_map(tree: ast.AST) -> dict[ast.AST, ast.AST]:
    return {child: parent for parent in ast.walk(tree) for child in ast.iter_child_nodes(parent)}


def _git_aware_context(node: ast.AST, parents: dict[ast.AST, ast.AST], source: str) -> bool:
    current = node
    while current in parents:
        current = parents[current]
        if isinstance(current, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            segment = ast.get_source_segment(source, current) or ""
            return any(marker in segment for marker in GIT_AWARE_MARKERS)
    segment = ast.get_source_segment(source, node) or ""
    return any(marker in segment for marker in GIT_AWARE_MARKERS)


def analyze_file(path: Path, repo_root: Path) -> list[dict[str, object]]:
    source = path.read_text(encoding="utf-8")
    try:
        tree = ast.parse(source, filename=str(path))
    except SyntaxError:
        return []

    parents = _parent_map(tree)
    findings: list[dict[str, object]] = []
    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        if not (_is_repo_wide_glob(node) or _is_repo_walk(node)):
            continue
        if _git_aware_context(node, parents, source):
            continue
        findings.append(
            {
                "path": str(path.relative_to(repo_root)),
                "line": getattr(node, "lineno", 1),
                "call": _call_label(node, source),
                "reason": "repo-wide filesystem traversal without an obvious gitignore-aware file source",
                "recommendation": (
                    "Prefer `git ls-files --cached --others --exclude-standard` or "
                    "`scripts.repo_file_listing.iter_matching_repo_files` before scanning."
                ),
            }
        )
    return findings


def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--repo-root", type=Path, required=True, help="Repo root for the gitignore scan-hygiene inventory")
    parser.add_argument("--path-glob", action="append", default=[], help="Glob of Python scanners to inspect (repeatable; defaults applied if omitted)")
    parser.add_argument("--exclude-glob", action="append", default=[], help="Glob of paths to exclude from the inventory (repeatable)")
    parser.add_argument("--require-empty", action="store_true", help="Exit non-zero when any non-git-aware repo traversal is found")
    parser.add_argument("--json", action="store_true", help="Emit the full inventory payload as JSON")
    parser.add_argument("--require-git-file-listing", action="store_true", help="Fail when git ls-files is unavailable for scanner discovery")
    args = parser.parse_args()

    repo_root = args.repo_root.resolve()
    path_globs = tuple(args.path_glob or DEFAULT_PATH_GLOBS)
    exclude_globs = tuple(args.exclude_glob or ())
    findings: list[dict[str, object]] = []
    for path in candidate_files(repo_root, path_globs, require_git=args.require_git_file_listing):
        rendered = str(path.relative_to(repo_root))
        if matches_any(rendered, exclude_globs):
            continue
        findings.extend(analyze_file(path, repo_root))

    payload = {
        "repo_root": str(repo_root),
        "path_globs": list(path_globs),
        "exclude_globs": list(exclude_globs),
        "findings": findings,
    }
    if args.json:
        print(json.dumps(payload, ensure_ascii=False, indent=2))
    else:
        for finding in findings:
            print(f"{finding['path']}:{finding['line']} {finding['reason']}")
            print(f"  call: {finding['call']}")
            print(f"  next: {finding['recommendation']}")
    return 1 if args.require_empty and findings else 0


if __name__ == "__main__":
    raise SystemExit(main())

